code = """import json
import pandas as pd

# Read children's books data
childrens_books = var_functions.query_db:10

# Read reviews from 2020 onwards
reviews_2020 = var_functions.query_db:8

# Convert to DataFrames
df_books = pd.DataFrame(childrens_books)
df_reviews = pd.DataFrame(reviews_2020)

# Extract book number from purchase_id to match with book_id
df_reviews['purchase_id_clean'] = df_reviews['purchase_id'].str.replace('purchaseid_', '')
df_books['book_id_clean'] = df_books['book_id'].str.replace('bookid_', '')

# Merge on the cleaned IDs
df_merged = pd.merge(df_books, df_reviews, left_on='book_id_clean', right_on='purchase_id_clean', how='inner')

# Calculate average rating per book
avg_ratings = df_merged.groupby(['book_id', 'title']).agg({
    'rating': ['mean', 'count']
}).round(2)

avg_ratings.columns = ['avg_rating', 'review_count']
avg_ratings = avg_ratings.reset_index()

# Convert rating to numeric (it's stored as string in some cases)
avg_ratings['avg_rating'] = pd.to_numeric(avg_ratings['avg_rating'], errors='coerce')

# Filter books with average rating >= 4.5
high_rated_books = avg_ratings[avg_ratings['avg_rating'] >= 4.5]

# Sort by average rating descending
high_rated_books = high_rated_books.sort_values('avg_rating', ascending=False)

result = high_rated_books.to_dict('records')

print('__RESULT__:')
print(json.dumps(result, indent=2))"""

